external_knowledge:
- Sessions in 2020 refer to those with a session_date that starts with '2020-';
- Average documents are calculated based on the count of documents per item, which is derived from the documents table.
- More than two items implies a count greater than 2.

sql:
SELECT title
FROM plenary_items
WHERE status = 'pending';

SELECT COUNT(item_id) 
FROM plenary_items 
WHERE plenary_date IS NULL AND status = 'pending';

SELECT amendment_id, amendment_text
FROM amendments
WHERE proposed_by = 'Jane Smith';

SELECT session_date, location
FROM plenary_sessions
ORDER BY session_date DESC;

SELECT COUNT(*) AS access_count
  FROM item_access_logs
  WHERE item_id = 0;

SELECT MAX(access_date) AS last_access_date
FROM item_access_logs
WHERE item_id = 0;

SELECT item_id, COUNT(access_id) AS access_count
FROM item_access_logs
GROUP BY item_id;
